import React from 'react';

const Header = () => {
  return (
    <header className="bg-blue-600 text-white text-center py-10">
      <h1 className="text-4xl font-bold">Welcome to EventHub</h1>
      <p className="mt-4 text-lg">Your go-to platform for event planning and management</p>
    </header>
  );
};

export default Header;
